import { PublicActionPage } from '@domain/publicActionPage';
import { LOCAL_DONOR_SESSION_STORAGE_KEY } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/utils/localDonorSession/constants';
import { useRollbar } from '@rollbar/react';
import clsx from 'clsx';
import { useCallback, useEffect } from 'react';
import { useFormContext } from 'react-hook-form';
import { Button } from 'src/builder/PublicActionPage/components/Button';
import { Label } from 'src/builder/PublicActionPage/components/Label';
import { Meta } from 'src/builder/PublicActionPage/components/Meta';
import storageAvailable from 'storage-available';

type DonorSessionBannerProps = {
  actionPage: PublicActionPage;
  isPastEvent: boolean;
};

export const DonorSessionBanner = ({ actionPage, isPastEvent }: DonorSessionBannerProps) => {
  const rollbar = useRollbar();
  const { setValue, watch } = useFormContext();
  const donorProfile = watch('donorProfile');
  const hasRestoredState = watch('hasRestoredState');
  const city = watch('addressAttributes.city');
  const country = watch('addressAttributes.country');
  const line1 = watch('addressAttributes.line1');
  const line2 = watch('addressAttributes.line2');
  const postalCode = watch('addressAttributes.postalCode');
  const region = watch('addressAttributes.region');
  const employerCity = watch('employerAddressAttributes.city');
  const employerCountry = watch('employerAddressAttributes.country');
  const employerLine1 = watch('employerAddressAttributes.line1');
  const employerLine2 = watch('employerAddressAttributes.line2');
  const employerPostalCode = watch('employerAddressAttributes.postalCode');
  const employerRegion = watch('employerAddressAttributes.region');
  const makeDonationAs = watch('makeDonationAs');
  const email = watch('email');
  const employed = watch('employed');
  const employerName = watch('employerName');
  const firstName = watch('firstName');
  const lastName = watch('lastName');
  const middleName = watch('middleName');
  const occupation = watch('occupation');
  const organization = watch('organization');
  const organizationType = watch('organizationType');
  const phone = watch('phone');
  const suffix = watch('suffix');
  const title = watch('title');
  const displayName = firstName || '';
  const displayNameForDescription = firstName || email || '';

  useEffect(() => {
    if (donorProfile) {
      setValue('hasRestoredState', false);
    }
  }, [donorProfile, setValue]);

  useEffect(() => {
    if (donorProfile || !storageAvailable('localStorage')) {
      return;
    }

    const session = {
      addressAttributes: {
        city,
        country,
        line1,
        line2,
        postalCode,
        region,
      },
      email,
      employed,
      employerAddressAttributes: {
        city: employerCity,
        country: employerCountry,
        line1: employerLine1,
        line2: employerLine2,
        postalCode: employerPostalCode,
        region: employerRegion,
      },
      employerName,
      firstName,
      lastName,
      makeDonationAs,
      middleName,
      occupation,
      organization,
      organizationType,
      phone,
      suffix,
      title,
    };

    try {
      window.localStorage.setItem(LOCAL_DONOR_SESSION_STORAGE_KEY, JSON.stringify(session));
    } catch (err) {
      rollbar?.error('Unable to store donor session info', { err });
    }
  }, [
    city,
    country,
    donorProfile,
    email,
    employed,
    employerCity,
    employerCountry,
    employerLine1,
    employerLine2,
    employerName,
    employerPostalCode,
    employerRegion,
    firstName,
    lastName,
    line1,
    line2,
    makeDonationAs,
    middleName,
    occupation,
    organization,
    organizationType,
    phone,
    postalCode,
    region,
    rollbar,
    suffix,
    title,
  ]);

  const resetDonorSession = useCallback(() => {
    [
      'email',
      'phone',
      'firstName',
      'lastName',
      'middleName',
      'title',
      'suffix',
      'addressAttributes.line1',
      'addressAttributes.line2',
      'addressAttributes.city',
      'addressAttributes.region',
      'addressAttributes.postalCode',
      'addressAttributes.country',
      'employerAddressAttributes.line1',
      'employerAddressAttributes.line2',
      'employerAddressAttributes.city',
      'employerAddressAttributes.region',
      'employerAddressAttributes.postalCode',
      'employerAddressAttributes.country',
      'employed',
      'employerName',
      'occupation',
      'organization',
      'organizationType',
    ].forEach((key) => {
      if (
        key === 'addressAttributes.country' &&
        actionPage?.fieldConfiguration.addressType === 'zip'
      ) {
        setValue(key, 'US');
      } else {
        setValue(key, '');
      }
    });

    setValue('makeDonationAs', 'individual');
    setValue('hasRestoredState', false);
  }, [actionPage?.fieldConfiguration.addressType, setValue]);

  const wrapperClasses = clsx(
    'ease animate-fade-in transition-all duration-200',
    isPastEvent ? 'mt-6' : 'mt-12'
  );

  return hasRestoredState ? (
    <div className={wrapperClasses} key="donor-session">
      <div className="flex flex-col items-center px-8">
        <Label className="mb-1" variant="medium">
          Welcome back, {displayName}
        </Label>
        <Meta variant="regular">
          {actionPage.pageType === 'donation' ? (
            <>
              No need to fill out your contact info again. Simply add your payment info to donate. (
              <Button
                className="!text-blue-600"
                key="reset-donor-session"
                onClick={resetDonorSession}
                variant="unstyled"
              >
                <Meta as="span">Not {displayNameForDescription}?</Meta>
              </Button>
              )
            </>
          ) : (
            <>
              No need to fill out your contact info again. (
              <Button
                className="!text-blue-600"
                key="reset-donor-session"
                onClick={resetDonorSession}
                variant="unstyled"
              >
                <Meta as="span">Not {displayNameForDescription}?</Meta>
              </Button>
              )
            </>
          )}
        </Meta>
      </div>
    </div>
  ) : null;
};
